import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { authService } from '../services/api';
import '../styles/auth.css';

const Login = () => {
    const navigate = useNavigate();
    const [formData, setFormData] = useState({ username: '', password: '' });
    const [error, setError] = useState('');
    const [loading, setLoading] = useState(false);

    const handleChange = (e) => {
        setFormData({ ...formData, [e.target.name]: e.target.value });
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        setError('');
        
        try {
            const response = await authService.login(formData);
            localStorage.setItem('access_token', response.data.access);
            localStorage.setItem('refresh_token', response.data.refresh);
            localStorage.setItem('user', JSON.stringify(response.data.user));
            
            const role = response.data.user.role;
            if (role === 'admin') {
                navigate('/admin/dashboard');
            } else if (role === 'doctor') {
                navigate('/doctor/dashboard');
            } else {
                navigate('/patient/dashboard');
            }
        } catch (err) {
            setError(err.response?.data?.detail || 'Login failed. Please try again.');
        } finally {
            setLoading(false);
        }
    };

    return React.createElement(
        'div',
        { className: 'auth-container' },
        React.createElement(
            'div',
            { className: 'auth-card' },
            React.createElement(
                'div',
                { className: 'auth-header' },
                React.createElement('h1', null, '🏥 Hospital Management System'),
                React.createElement('p', null, 'Login to your account')
            ),
            error && React.createElement('div', { className: 'alert alert-error' }, error),
            React.createElement(
                'form',
                { onSubmit: handleSubmit, className: 'auth-form' },
                React.createElement(
                    'div',
                    { className: 'form-group' },
                    React.createElement('label', { htmlFor: 'username' }, 'Username'),
                    React.createElement('input', {
                        type: 'text',
                        id: 'username',
                        name: 'username',
                        value: formData.username,
                        onChange: handleChange,
                        required: true,
                        placeholder: 'Enter your username',
                    })
                ),
                React.createElement(
                    'div',
                    { className: 'form-group' },
                    React.createElement('label', { htmlFor: 'password' }, 'Password'),
                    React.createElement('input', {
                        type: 'password',
                        id: 'password',
                        name: 'password',
                        value: formData.password,
                        onChange: handleChange,
                        required: true,
                        placeholder: 'Enter your password',
                    })
                ),
                React.createElement(
                    'button',
                    { type: 'submit', disabled: loading, className: 'btn btn-primary' },
                    loading ? 'Logging in...' : 'Login'
                )
            ),
            React.createElement(
                'div',
                { className: 'auth-footer' },
                React.createElement(
                    'p',
                    null,
                    'Don\'t have an account? ',
                    React.createElement(Link, { to: '/register' }, 'Register here')
                )
            )
        )
    );
};

export default Login;
